.darma-loader-darma-custom-445 {color: var(--loader-color, #0891b2);
   width: 50px;
   aspect-ratio: 1;
   box-shadow: 0 0 0 3px currentColor inset;
   border-radius: 50%;
   position: relative;
   animation: darma-loader-darma-custom-445-l6 1.5s linear infinite;
}
.darma-loader-darma-custom-445:before  {
  content: "";
   position: absolute;
   top: 100%;
   box-shadow: inherit;
   width: 25px;
   aspect-ratio: 1;
   border-radius: 50%;
}
@keyframes darma-loader-darma-custom-445-l6  {
  to  {
  transform: rotate(360deg);
}
}

